// ============================================================
// NUTRIDIET MARKET — LOGICA DEL BOT
// Reemplazar los valores marcados con TODO antes de activar
// ============================================================

const CBU           = 'TODO_CBU_AQUI';          // ej: 0720461088000054321874
const ALIAS_CBU     = 'TODO_ALIAS_AQUI';        // ej: NUTRIDIET.MKT
const ALIAS_MP      = 'TODO_ALIAS_MP_AQUI';     // ej: nutridiet.market
const ALIAS_NAVE    = 'TODO_ALIAS_NAVE_AQUI';   // ej: nutridiet.nave
const TEL_EMPLEADO  = 'TODO_TEL_EMPLEADO';      // ej: 5492216993344 (con codigo pais, sin +)

// ------------------------------------------------------------
// Datos del mensaje entrante
// ------------------------------------------------------------
const campos  = $('Set Campos').first().json;
const telefono       = campos.telefono;
const tipo_msg       = campos.tipo_msg;
const phone_number_id = campos.phone_number_id;
const mensaje = (campos.mensaje || '').toLowerCase().trim();

// ------------------------------------------------------------
// Estado actual del usuario (desde Google Sheets)
// ------------------------------------------------------------
let estado = 'nuevo';
let datos  = {};

const filas = $input.all();
if (filas.length > 0 && filas[0].json.ESTADO) {
  estado = filas[0].json.ESTADO;
  try { datos = JSON.parse(filas[0].json.DATOS || '{}'); } catch(e) { datos = {}; }
}

// ------------------------------------------------------------
// Variables de salida
// ------------------------------------------------------------
let response_text        = '';
let nuevo_estado         = estado;
let nuevos_datos         = { ...datos };
let notificar_empleado   = false;
let msg_empleado         = '';

// ============================================================
// LOGICA PRINCIPAL
// ============================================================

if (tipo_msg === 'image' && estado === 'esperando_pago') {
  // Imagen = comprobante de pago
  response_text = '¡Recibimos tu comprobante! 🎉\n\nEstamos verificando el pago. En los próximos minutos te confirmamos y preparamos tu pedido 💪\n\n_¡Gracias por elegirnos, ' + (datos.nombre || '') + '!_ 🌿';
  nuevo_estado  = 'pago_recibido';
  notificar_empleado = true;
  msg_empleado = '⚠️ *NUEVO PEDIDO CON COMPROBANTE* ⚠️\n\n📞 Teléfono: ' + telefono + '\n👤 Nombre: ' + (datos.nombre || 'sin nombre') + '\n🛒 Productos: ' + (datos.productos || 'ver chat') + '\n📍 Entrega: ' + (datos.tipo_entrega === 'retiro' ? 'Retiro en tienda' : datos.direccion || 'sin dirección') + '\n💳 Pago: ' + (datos.metodo_pago || 'transferencia') + '\n\nVerificar pago y confirmar.';

} else if (tipo_msg === 'text') {

  // ----------------------------------------------------------
  // Estado: NUEVO o COMPLETADO → mostrar bienvenida
  // ----------------------------------------------------------
  if (estado === 'nuevo' || estado === 'completado') {
    response_text = '¡Hola! 👋 Bienvenido/a a *NutriDiet Market* 🌿\n\nSomos tu supermercado natural en La Plata: alimentos saludables, suplementos, cosmética natural y bazar decorativo. Enviamos a todo el país 🚚\n\n¿En qué te puedo ayudar hoy?\n\n🛒 *1* — Ver catálogo de productos\n📦 *2* — Hacer un pedido\n🚚 *3* — Consultar envíos y costos\n📍 *4* — Horarios y dirección del local\n💬 *5* — Hablar con una persona del equipo\n\n_Respondé con el número de tu elección_ 😊';
    nuevo_estado  = 'menu_mostrado';
    nuevos_datos  = {};

  // ----------------------------------------------------------
  // Estado: MENU MOSTRADO → procesar opción elegida
  // ----------------------------------------------------------
  } else if (estado === 'menu_mostrado') {
    if (mensaje === '1') {
      response_text = '¡Perfecto! Acá podés ver todo nuestro catálogo 👇\n\nTenemos más de 500 productos en estas categorías:\n🥦 *Alimentos naturales* — granolas, frutos secos, semillas, snacks, harinas, legumbres, aceites\n💊 *Suplementos* — proteínas, colágeno, vitaminas, minerales, antioxidantes\n🧴 *Cosmética natural* — cuidado de piel, cabello y cuerpo\n🏡 *NutHome* — bazar y decoración sustentable\n\n¿Estás buscando algo en particular o querés que te recomiende? Contame 😊';
      nuevo_estado = 'catalogo';
    } else if (mensaje === '2') {
      response_text = '¡Genial, armemos tu pedido! 🛒\n\nDecime qué productos querés y la cantidad de cada uno.\n\nPor ejemplo:\n_"2 granolas sin azúcar, 1 colágeno 300g y 1 proteína vainilla"_\n\n¡Escribime lo que querés! 😊';
      nuevo_estado = 'esperando_productos';
    } else if (mensaje === '3') {
      response_text = '¡Claro! Acá te cuento todo sobre los envíos 📦\n\n*Enviamos a todo el país* a través de ShipNow 🚚\n\n📋 *Tiempos de entrega:*\n• CABA y GBA: 24-48 horas hábiles\n• Interior del país: 3-5 días hábiles\n• La Plata y alrededores: 24-48 horas hábiles\n\n📦 *Retiro sin cargo:*\nPodés retirar gratis en nuestro local:\n📍 Av. 7 e/34 y 35 nº 136, La Plata\n\n¿Querés que te calcule el costo a tu zona? Mandame tu código postal 😊';
      nuevo_estado = 'menu_mostrado';
    } else if (mensaje === '4') {
      response_text = '¡Con gusto! Acá tenés todo sobre nuestro local 📍\n\n🏪 *NutriDiet Market*\nAv. 7 e/34 y 35 nº 136, La Plata, Buenos Aires\n\n🕘 *Horarios de atención:*\n• Lunes a Viernes: 9:00 a 20:00 hs\n• Sábados: 10:00 a 19:00 hs\n• Domingos: cerrado\n\n🗺️ Google Maps: https://maps.google.com/?q=Av+7+136+La+Plata\n\n¿Puedo ayudarte con algo más? 😊';
      nuevo_estado = 'menu_mostrado';
    } else if (mensaje === '5') {
      response_text = 'Disculpá, voy a pasarte con una persona de nuestro equipo 💚\n\nEn un momento te atienden 🙏';
      nuevo_estado = 'agente';
      notificar_empleado = true;
      msg_empleado = '💬 *CLIENTE SOLICITA ATENCIÓN HUMANA*\n\nTeléfono: ' + telefono + '\nEstado anterior: ' + estado;
    } else {
      response_text = 'Hmm, no entendí bien tu mensaje 😅\n\n¿Querés que te muestre el menú de opciones?\n\n🛒 *1* — Ver catálogo\n📦 *2* — Hacer un pedido\n🚚 *3* — Envíos\n📍 *4* — Horarios y local\n💬 *5* — Hablar con una persona';
      nuevo_estado = 'menu_mostrado';
    }

  // ----------------------------------------------------------
  // Estado: CATÁLOGO → guiar al pedido
  // ----------------------------------------------------------
  } else if (estado === 'catalogo') {
    response_text = '¡Gracias por contarme! 🔍\n\n¿Querés que arme el pedido directamente? Decime el producto y la cantidad y en un segundo te tengo el total 🛒';
    nuevo_estado = 'esperando_productos';

  // ----------------------------------------------------------
  // Estado: ESPERANDO PRODUCTOS
  // ----------------------------------------------------------
  } else if (estado === 'esperando_productos') {
    nuevos_datos.productos = campos.mensaje;
    response_text = 'Anotado! 📝 Recibí tu pedido:\n\n🛒 *Productos:*\n_"' + campos.mensaje + '"_\n\n¿Es correcto? Respondé *SI* para confirmar o contame qué cambiar ✅';
    nuevo_estado = 'esperando_confirmacion';

  // ----------------------------------------------------------
  // Estado: ESPERANDO CONFIRMACIÓN
  // ----------------------------------------------------------
  } else if (estado === 'esperando_confirmacion') {
    if (mensaje.includes('si') || mensaje.includes('sí') || mensaje === 'ok' || mensaje === 'confirmo') {
      response_text = 'Perfecto! ¿Cómo preferís recibir tu pedido?\n\n🏠 *1* — Envío a domicilio\n🏪 *2* — Retiro en el local sin cargo\n_(Av. 7 e/34 y 35 nº 136, La Plata)_';
      nuevo_estado = 'esperando_tipo_entrega';
    } else {
      response_text = '¡No hay problema! Contame qué querés cambiar y lo ajustamos 😊';
      nuevo_estado = 'esperando_productos';
    }

  // ----------------------------------------------------------
  // Estado: ESPERANDO TIPO DE ENTREGA
  // ----------------------------------------------------------
  } else if (estado === 'esperando_tipo_entrega') {
    if (mensaje === '1') {
      response_text = '¡Perfecto! Para calcular el envío necesito:\n\n📍 Calle y número\n🏙️ Ciudad y provincia\n📮 Código postal\n\nPodés mandarlo todo junto en un mensaje 😊';
      nuevos_datos.tipo_entrega = 'envio';
      nuevo_estado = 'esperando_direccion';
    } else if (mensaje === '2') {
      response_text = '¡Genial! Podés retirar tu pedido en:\n\n📍 *Av. 7 e/34 y 35 nº 136, La Plata*\n🕘 Lun a Vie: 9:00-20:00 / Sáb: 10:00-19:00\n\nTe avisamos cuando esté listo 💚\n\nAhora necesito tu *nombre y apellido completo* 👇';
      nuevos_datos.tipo_entrega = 'retiro';
      nuevos_datos.direccion = 'Retiro en tienda';
      nuevo_estado = 'esperando_nombre';
    } else {
      response_text = 'Por favor respondé *1* para envío a domicilio o *2* para retiro en el local 😊';
    }

  // ----------------------------------------------------------
  // Estado: ESPERANDO DIRECCIÓN
  // ----------------------------------------------------------
  } else if (estado === 'esperando_direccion') {
    nuevos_datos.direccion = campos.mensaje;
    response_text = 'Perfecto! Anotamos la dirección 📍\n\nAhora necesito tu *nombre y apellido completo* para registrar el pedido 👇';
    nuevo_estado = 'esperando_nombre';

  // ----------------------------------------------------------
  // Estado: ESPERANDO NOMBRE
  // ----------------------------------------------------------
  } else if (estado === 'esperando_nombre') {
    nuevos_datos.nombre = campos.mensaje;
    const nombre_corto = campos.mensaje.split(' ')[0];
    response_text = '¡Gracias, ' + nombre_corto + '! 😊 Ya casi terminamos.\n\n¿Cómo querés pagar?\n\n💳 *1* — Transferencia bancaria / CBU\n📱 *2* — Mercado Pago\n🔵 *3* — Nave\n💵 *4* — Efectivo (solo retiro en tienda)';
    nuevo_estado = 'esperando_eleccion_pago';

  // ----------------------------------------------------------
  // Estado: ESPERANDO ELECCIÓN DE PAGO
  // ----------------------------------------------------------
  } else if (estado === 'esperando_eleccion_pago') {
    if (mensaje === '1') {
      nuevos_datos.metodo_pago = 'transferencia';
      response_text = '¡Perfecto! Hacé la transferencia a:\n\n🏦 *CBU:* ' + CBU + '\n📛 *Titular:* NutriDiet Market\n🔖 *Alias:* ' + ALIAS_CBU + '\n\nUna vez que tengas el comprobante envialo acá como foto 📸 y confirmamos tu pedido al toque 💚';
      nuevo_estado = 'esperando_pago';
    } else if (mensaje === '2') {
      nuevos_datos.metodo_pago = 'mercadopago';
      response_text = '¡Perfecto! Podés pagar por Mercado Pago:\n\n📱 *Alias MP:* ' + ALIAS_MP + '\n\nUna vez que pagues envianos el comprobante acá 📸 💚';
      nuevo_estado = 'esperando_pago';
    } else if (mensaje === '3') {
      nuevos_datos.metodo_pago = 'nave';
      response_text = '¡Perfecto! Podés pagar por Nave:\n\n📱 *Alias:* ' + ALIAS_NAVE + '\n\nUna vez que pagues envianos el comprobante acá 📸 💚';
      nuevo_estado = 'esperando_pago';
    } else if (mensaje === '4') {
      nuevos_datos.metodo_pago = 'efectivo';
      response_text = '¡Perfecto! Abonás en efectivo cuando venís a retirar al local 💵\n\n📍 *Av. 7 e/34 y 35 nº 136, La Plata*\n🕘 Lun-Vie: 9:00-20:00 / Sáb: 10:00-19:00\n\nTe avisamos cuando el pedido esté listo 📲\n\n¡Gracias por elegirnos! 🌿';
      nuevo_estado = 'pago_recibido';
      notificar_empleado = true;
      msg_empleado = '⚠️ *NUEVO PEDIDO — PAGO EFECTIVO* ⚠️\n\n📞 Teléfono: ' + telefono + '\n👤 Nombre: ' + (nuevos_datos.nombre || '') + '\n🛒 Productos: ' + (datos.productos || '') + '\n📍 Entrega: Retiro en tienda\n💳 Pago: Efectivo';
    } else {
      response_text = 'Por favor elegí una opción:\n\n💳 *1* — Transferencia\n📱 *2* — Mercado Pago\n🔵 *3* — Nave\n💵 *4* — Efectivo (retiro en tienda)';
    }

  // ----------------------------------------------------------
  // Estado: ESPERANDO PAGO
  // ----------------------------------------------------------
  } else if (estado === 'esperando_pago') {
    response_text = 'Todavía estamos esperando el comprobante de pago 📸\n\nCuando lo tengas envialo acá como foto y confirmamos tu pedido 💚';

  // ----------------------------------------------------------
  // Estado: AGENTE / PAGO RECIBIDO
  // ----------------------------------------------------------
  } else if (estado === 'agente' || estado === 'pago_recibido') {
    response_text = 'En breve un miembro de nuestro equipo te responde 💚\n\n¡Gracias por tu paciencia! 🌿';

  // ----------------------------------------------------------
  // Catch-all → mostrar menú
  // ----------------------------------------------------------
  } else {
    response_text = '¡Hola! 👋 ¿En qué te puedo ayudar?\n\n🛒 *1* — Ver catálogo\n📦 *2* — Hacer un pedido\n🚚 *3* — Envíos\n📍 *4* — Horarios y local\n💬 *5* — Hablar con una persona';
    nuevo_estado = 'menu_mostrado';
  }

} else {
  response_text = '¡Hola! Por el momento proceso mensajes de texto e imágenes 📱\nEscribime cualquier cosa y te ayudo 😊';
}

return [{
  json: {
    telefono,
    phone_number_id,
    response_text,
    nuevo_estado,
    nuevos_datos:       JSON.stringify(nuevos_datos),
    notificar_empleado,
    msg_empleado,
    tel_empleado:       TEL_EMPLEADO
  }
}];
